#!/usr/bin/env node
// apply_fixes.js — تشغيله: node apply_fixes.js
const fs = require('fs');
const path = require('path');

const BANK_B64 = '';
const INDEX_B64 = '';

function w(file, b64) {
  const dir = path.dirname(file);
  if (!fs.existsSync(dir)) fs.mkdirSync(dir, {recursive:true});
  // backup
  if (fs.existsSync(file)) fs.copyFileSync(file, file + '.bak');
  fs.writeFileSync(file, Buffer.from(b64, 'base64'));
  console.log('✅ كُتب: ' + file);
}

// حذف patch scripts
const toDelete = [
  'fix_answer_display.cjs','fix_currentq.cjs','fix_forcestart.cjs',
  'fix_games_panel.cjs','fix_lifeline.cjs','fix_million_edit.cjs',
  'fix_million_final.cjs','patch_master.cjs','bot/commands.js.orig'
];
toDelete.forEach(f => {
  if (fs.existsSync(f)) { fs.unlinkSync(f); console.log('🗑️  حُذف: ' + f); }
});

w('handlers/bank.js', BANK_B64);
w('index.js', INDEX_B64);

console.log('');
console.log('✅ جميع الإصلاحات اكتملت!');
console.log('');
console.log('الخطوة التالية:');
console.log('  git add -A');
console.log('  git commit -m "fix: atomic bank, nested middleware, duplicate triggers"');
console.log('  git push');
